@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @oninput="OnSearchInput"
           value="@_query" />

    @if (_isLoading)
    {
        <div class="product-search-status">Searching…</div>
    }
    else if (_error is not null)
    {
        <div class="product-search-error">
            <span>Search failed: @_error</span>
            <button @onclick="RetrySearch">Retry</button>
        </div>
    }
    else if (_hasSearched && _results.Count == 0)
    {
        <div class="product-search-status">No products found.</div>
    }

    @if (_results.Count > 0)
    {
        <div class="product-search-results">
            @foreach (var product in _results)
            {
                <div class="product-card" @onclick="() => SelectProduct(product)">
                    <img src="@product.ImageUrl" alt="@product.Name" loading="lazy" />
                    <div class="product-card-body">
                        <h4>@product.Name</h4>
                        <span class="product-card-price">@product.Price.ToString("C")</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string _query = string.Empty;
    private List<Product> _results = new();
    private bool _isLoading;
    private bool _hasSearched;
    private string? _error;

    private Timer? _debounceTimer;
    private CancellationTokenSource? _searchCts;
    private bool _disposed;

    private void OnSearchInput(ChangeEventArgs e)
    {
        _query = e.Value?.ToString() ?? string.Empty;

        // Cancel any in-flight search immediately so we don't process stale results.
        CancelPendingSearch();

        _debounceTimer?.Dispose();
        _debounceTimer = new Timer(OnDebounceElapsed, null, 300, Timeout.Infinite);
    }

    private async void OnDebounceElapsed(object? state)
    {
        if (_disposed)
            return;

        // Capture the query at debounce time so a later keystroke can't mutate it.
        var query = _query;

        if (string.IsNullOrWhiteSpace(query))
        {
            await InvokeAsync(() =>
            {
                _results = new();
                _hasSearched = false;
                _error = null;
                _isLoading = false;
                StateHasChanged();
            });
            return;
        }

        var cts = new CancellationTokenSource();
        _searchCts = cts;

        await InvokeAsync(() =>
        {
            _isLoading = true;
            _error = null;
            StateHasChanged();
        });

        try
        {
            var results = await ProductService.SearchAsync(query, cts.Token);

            if (!cts.Token.IsCancellationRequested)
            {
                await InvokeAsync(() =>
                {
                    _results = results;
                    _hasSearched = true;
                    _isLoading = false;
                    StateHasChanged();
                });
            }
        }
        catch (OperationCanceledException)
        {
            // Search was superseded by a newer query — nothing to do.
        }
        catch (Exception ex)
        {
            if (!cts.Token.IsCancellationRequested)
            {
                await InvokeAsync(() =>
                {
                    _error = ex.Message;
                    _isLoading = false;
                    StateHasChanged();
                });
            }
        }
        finally
        {
            cts.Dispose();
        }
    }

    private void RetrySearch()
    {
        _error = null;
        _debounceTimer?.Dispose();
        _debounceTimer = new Timer(OnDebounceElapsed, null, 0, Timeout.Infinite);
    }

    private async Task SelectProduct(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private void CancelPendingSearch()
    {
        try { _searchCts?.Cancel(); }
        catch (ObjectDisposedException) { }
    }

    public void Dispose()
    {
        _disposed = true;
        _debounceTimer?.Dispose();
        CancelPendingSearch();
    }
}

